const textLength = (value: unknown): number => {
  if (value === null || value === undefined) return 0;
  if (typeof value === "string") return value.length;
  return JSON.stringify(value).length;
};

const memoryLength =
  textLength(ctx.state.summary) +
  textLength(ctx.state.new_events);

return {
  setLocals: {
    memory_over_limit: memoryLength > 4000,
  },
};

const asRecord = (value: unknown): Record<string, unknown> => {
  if (value && typeof value === "object" && !Array.isArray(value)) return value as Record<string, unknown>;
  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value) as unknown;
      return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed as Record<string, unknown> : {};
    } catch { return {}; }
  }
  return {};
};
const result = asRecord(ctx.locals.state_sampled_task_result);
const records = Array.isArray(result.records) ? result.records : [];
const sampledTaskRow = asRecord(records[0]);
const sampledTask = asRecord(sampledTaskRow.profile);
const taskId = String(sampledTaskRow.task_id ?? sampledTask.task_id ?? "").trim();
if (!taskId) throw new Error("The sampled task is missing task_id.");
return {
  setLocals: {
    sampled_task_for_run: sampledTask,
    sampled_task_id_for_run: taskId,
    task_id: taskId,
  },
};

const asRecord = (value: unknown): Record<string, unknown> => {
  if (value && typeof value === "object" && !Array.isArray(value)) return value as Record<string, unknown>;
  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value) as unknown;
      return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed as Record<string, unknown> : {};
    } catch { return {}; }
  }
  return {};
};
const sampledTask = asRecord(ctx.locals.sampled_task_for_run);
const trajectoryResult = asRecord(ctx.locals.state_sampled_trajectory_result);
const trajectoryRecords = Array.isArray(trajectoryResult.records) ? trajectoryResult.records : [];
const sampledTrajectory = asRecord(trajectoryRecords[0]);
if (String(sampledTrajectory.task_id ?? "") !== String(ctx.locals.sampled_task_id_for_run ?? "")) {
  throw new Error("No price trajectory is associated with the sampled task.");
}
return {
  setState: {
    selected_task_id: String(ctx.locals.sampled_task_id_for_run ?? ""),
    selected_task: sampledTask,
    selected_price_trajectory: sampledTrajectory,
  },
};
